    const files = this.getAllCodeFiles();
    
    for (const file of files) {
      const issues = await this.scanFileForPerformance(file);
      performanceIssues.push(...issues);
    }
    
    // Analysiere Performance-Muster über alle Dateien
    const performancePatterns = this.analyzePerformancePatterns(performanceIssues);
    
    return {
      issues: performanceIssues,
      patterns: performancePatterns
    };
