  analyzePerformancePatterns(performanceIssues) {
    const patterns = {
      totalIssues: performanceIssues.length,
      byType: {},
      bySeverity: {},
      byFile: {},
      recommendations: []
    };
    
    // Gruppiere nach Typ
    for (const issue of performanceIssues) {
      if (!patterns.byType[issue.type]) {
        patterns.byType[issue.type] = 0;
      }
      patterns.byType[issue.type]++;
      
      if (!patterns.bySeverity[issue.severity]) {
        patterns.bySeverity[issue.severity] = 0;
      }
      patterns.bySeverity[issue.severity]++;
      
      if (!patterns.byFile[issue.file]) {
        patterns.byFile[issue.file] = 0;
      }
      patterns.byFile[issue.file]++;
    }
    
    // Generiere Empfehlungen basierend auf Mustern
    if (patterns.byType['inefficient-loop'] > 5) {
      patterns.recommendations.push({
        type: 'loop-optimization',
        priority: 'high',
        message: 'Multiple inefficient loops detected - consider using array methods like map/filter/reduce'
      });
    }
    
    if (patterns.byType['dom-query'] > 10) {
      patterns.recommendations.push({
        type: 'dom-caching',
        priority: 'medium',
        message: 'Frequent DOM queries detected - consider caching DOM elements'
      });
    }
    
    if (patterns.bySeverity['low'] > 20) {
      patterns.recommendations.push({
        type: 'code-review',
        priority: 'low',
        message: 'Many low-severity performance issues - consider code review'
      });
    }
    
    return patterns;
  }

