  async analyzeFile(filePath) {
    const content = fs.readFileSync(filePath, 'utf8');
    const ext = path.extname(filePath);
    
    const issues = [];
    
    // Syntax-Check
    try {
      if (ext === '.js' || ext === '.mjs') {
        new Function(content);
      }
    } catch (error) {
      issues.push({
        file: filePath,
        type: 'syntax',
        severity: 'critical',
        message: error.message,
        fixable: true
      });
    }
    
    // Code-Quality-Check
    const qualityIssues = this.checkCodeQuality(content, filePath);
    issues.push(...qualityIssues);
    
    return { issues };
  }

  async scanFileForErrors(filePath) {
    const content = fs.readFileSync(filePath, 'utf8');
    const errors = [];
    
    // Common Error Patterns
    const errorPatterns = [
      { pattern: /console\.log\(/, type: 'debug', severity: 'low', fixable: true },
      { pattern: /var\s+\w+/, type: 'deprecated', severity: 'low', fixable: true },
      { pattern: /=== \s*[^=]/, type: 'comparison', severity: 'medium', fixable: true },
      { pattern: /catch\s*\(\s*\)/, type: 'error-handling', severity: 'medium', fixable: true }
    ];
    
    const lines = content.split('\n');
    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];
      const lineNum = i + 1;
      
      for (const { pattern, type, severity, fixable } of errorPatterns) {
        if (pattern.test(line)) {
          errors.push({
            file: filePath,
            line: lineNum,
            type,
            severity,
            message: `${type} issue detected`,
            fixable
          });
        }
      }
    }
    
    return errors;
  }

  async scanFileForSecurity(filePath) {
    const content = fs.readFileSync(filePath, 'utf8');
    const issues = [];
    
    // Security Patterns
    const securityPatterns = [
      { pattern: /password\s*=\s*['"`][^'"`]+['"`]/, type: 'hardcoded-password', severity: 'critical' },
      { pattern: /api[_-]?key\s*=\s*['"`][^'"`]+['"`]/, type: 'hardcoded-api-key', severity: 'critical' },
      { pattern: /secret\s*=\s*['"`][^'"`]+['"`]/, type: 'hardcoded-secret', severity: 'critical' },
      { pattern: /innerHTML\s*=/, type: 'xss-risk', severity: 'high' },
      { pattern: /eval\(/, type: 'eval-risk', severity: 'high' }
    ];
    
    const lines = content.split('\n');
    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];
      const lineNum = i + 1;
      
      for (const { pattern, type, severity } of securityPatterns) {
        if (pattern.test(line)) {
          issues.push({
            file: filePath,
            line: lineNum,
            type,
            severity,
            message: `Security issue: ${type}`,
            fixable: false
          });
        }
      }
    }
    
    return issues;
  }

  async scanFileForPerformance(filePath) {
    const content = fs.readFileSync(filePath, 'utf8');
    const issues = [];
    
    // Performance Patterns
    const performancePatterns = [
      { pattern: /for\s*\(\s*.*\s*in\s*.*\.length\s*\)/, type: 'inefficient-loop', severity: 'low' },
      { pattern: /document\.getElementById\s*\(/, type: 'dom-query', severity: 'low' },
      { pattern: /\.addEventListener\s*\(/, type: 'event-listener', severity: 'low' }
    ];
    
    const lines = content.split('\n');
    for (let i = 0; i < lines.length; i++) {
      const line = lines[i];
      const lineNum = i + 1;
      
      for (const { pattern, type, severity } of performancePatterns) {
        if (pattern.test(line)) {
          issues.push({
            file: filePath,
            line: lineNum,
            type,
            severity,
            message: `Performance issue: ${type}`,
            fixable: true
          });
        }
      }
    }
    
    return issues;
  }

  async fixError(error) {
    try {
      const content = fs.readFileSync(error.file, 'utf8');
      const lines = content.split('\n');
      
      if (error.line && lines[error.line - 1]) {
        const originalLine = lines[error.line - 1];
        const fixedLine = this.applyFix(originalLine, error.type);
        
        lines[error.line - 1] = fixedLine;
        const fixedContent = lines.join('\n');
        
        fs.writeFileSync(error.file, fixedContent);
        
        return {
          success: true,
          file: error.file,
          line: error.line,
          original: originalLine,
          fixed: fixedLine,
          type: error.type
        };
      }
    } catch (error) {
      console.error(`Fix fehlgeschlagen für ${error.file}:`, error);
    }
    
    return { success: false, error };
  }

